JsonJSTransformerProvider.initializationScript:
function transform(document, context) {
  if (!document) throw Error("No document provided");

  const indexMap = document.get("index");
  const sourceMap = document.get("source");
  const originalId = indexMap.get("_id");

  const results = [];
  const iterations = 10000;

  for (let k = 1; k <= iterations; k++) {
    const newIndex = new Map(indexMap);
    const newSource = new Map(sourceMap);

    newIndex.set("_id", `${originalId}_${k}`);
    newIndex.set("_index", indexMap.get("_index").replace("largetest", "new_largetest"));

    const originalNum = sourceMap.get("doc_number");
    newSource.set("doc_number", originalNum * 10000 + k);

    results.push(new Map([
      ["index", newIndex],
      ["source", newSource]
    ]));
  }
  return results;
}
